package com.softwarerandomization.corruption;

import com.softwarerandomization.corruption.types.*;

import java.io.File;
import java.util.ArrayList;
import java.util.List;
import java.util.Random;

/**
 * Class to apply mutations to a file.
 *
 * @author Michael J. Ryan
 */
public class Corruption {

    private Random random;
    private List<CorruptionType> corruptionTypes;

    /**
     * Default Constructor.
     */
    public Corruption() {
        this(new Random());
    }

    /**
     * Constructor with a random number generator.
     *
     * @param random Random number generator.
     */
    public Corruption(Random random) {
        this.random = random;
        this.corruptionTypes = new ArrayList<>();
        this.corruptionTypes.add(new AddCorruption());
        this.corruptionTypes.add(new DeleteCorruption());
        this.corruptionTypes.add(new ModifyCorruption());
        this.corruptionTypes.add(new MoveCorruption());
        this.corruptionTypes.add(new MoveCorruptionWithRandomBlock());
        this.corruptionTypes.add(new MoveCorruptionWithRandomBlockBySize());
        this.corruptionTypes.add(new MoveCorruptionWithRandomBlockBySizeAndType());
        this.corruptionTypes.add(new MoveCorruptionWithRandomBlockByType());
    }

    /**
     * Apply a mutation.
     *
     * @param file      File to mutate.
     * @param mutation  Mutation to apply.
     * @param mutationType Mutation type to use.
     * @return New file.
     */
    public File apply(File file, Mutation mutation, MutationType mutationType) {
        CorruptionType corruptionType = CorruptionFactory.getCorruptionType(corruptionTypes, mutationType);
        return corruptionType.apply(file, mutation);
    }

    /**
     * Get a random mutation.
     *
     * @param file File to mutate.
     * @return Random mutation.
     */
    public Mutation getRandomMutation(File file) {
        return CorruptionFactory.getRandomMutation(corruptionTypes, file);
    }

